// ✅ BOM - CSRF token
// 1. Backend envia CSRF token em cookie não-HttpOnly
// 2. Frontend lê e envia no header de cada mutação

function getCsrfToken(): string {
  return document.cookie
    .split('; ')
    .find(c => c.startsWith('csrf-token='))
    ?.split('=')[1] ?? '';
}

