function TransferForm() {
  const mutation = useMutation({
    mutationFn: (data: TransferData) =>
      api.post('/transfer', data),
  });

  return (
    <button
      onClick={() => mutation.mutate(data)}
      disabled={mutation.isPending} // Desabilita durante request
    >
      {mutation.isPending ? 'Processando...' : 'Transferir'}
    </button>
  );
}

// ✅ MELHOR - Idempotency key previne duplicação
import { v4 as uuid } from 'uuid';

function TransferForm() {
  const [idempotencyKey] = useState(() => uuid());

  const mutation = useMutation({
    mutationFn: (data: TransferData) =>
      api.post('/transfer', data, {
        headers: { 'Idempotency-Key': idempotencyKey },
      }),
  });

  // Mesmo se o request for enviado 2x, o backend
  // identifica pelo idempotency key e executa só 1x
  return (
    <button
      onClick={() => mutation.mutate(data)}
      disabled={mutation.isPending}
    >
      Transferir
    </button>
  );
}
